mapper.delete:
DELETE
FROM conf_distributed_lock

WHERE lock_key = #{lockKey}
  AND lock_value = #{lockValue}

mapper.update:
UPDATE conf_distributed_lock

SET expire           = #{newExpire},
    expire_timestamp = #{newExpireTimestamp}

WHERE lock_key = #{lockKey}
  AND lock_value = #{lockValue}
  AND expire_timestamp > UNIX_TIMESTAMP() * 1000

mapper.select:
SELECT id, lock_key, lock_value, expire, expire_timestamp FROM conf_distributed_lock
WHERE expire_timestamp < #{currentTime}
ORDER BY expire_timestamp ASC LIMIT 1000

mapper.delete:
DELETE FROM conf_distributed_lock

WHERE id IN

    #{lockId}
